@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle italic
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor black
skinparam classArrowColor black
skinparam classStereotypeStyle none

class "Creator" as Creator {
    + factoryMethod()
}
class "ConcreteCreator" as ConcreteCreator {
    + factoryMethod()
}
class "Product" as Product {
}
class "ConcreteProduct" as ConcreteProduct {
}
class "Device" as Device {
}
class "PC" as PC {
}
class "Laptop" as Laptop {
}
class "Phone" as Phone {
}

Creator <|-- ConcreteCreator
Product <|-- ConcreteProduct
Device <|-- PC
Device <|-- Laptop
Device <|-- Phone
ConcreteCreator --> ConcreteProduct

note top of Creator
    <b>I</b>
end note
note top of ConcreteCreator
    <b>C</b>
end note
note top of Product
    <b>I</b>
end note
note top of ConcreteProduct
    <b>C</b>
end note
note top of Device
    <b>I</b>
end note
note top of PC
    <b>C</b>
end note
note top of Laptop
    <b>C</b>
end note
note top of Phone
    <b>C</b>
end note

@enduml
